/**
 * M1 codes identifying specific Fair Housing training courses completed by a member.
 * These are tracked as part of the NAR Code of Ethics (COE) compliance requirements.
 * - `"FHVN"` — Fair Housing: It's Your Duty (video)
 * - `"BOVR"` — Bias Override: Overcoming Barriers to Fair Housing
 * - `"HWD"` — Fairhaven (online simulation)
 * - `"FAIRH"` — Other approved Fair Housing course
 */
export type FairHousingTypeCode = "FHVN" | "BOVR" | "HWD" | "FAIRH";